import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { ZeusStatsParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/roleplay/ZeusStatsParser';

export class ZeusHealthEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, ZeusStatsParser);
    }

    public getParser(): ZeusStatsParser {
        return this.parser as ZeusStatsParser;
    }
}
